"from rest_framework.decorators import api_view, permission_classes\nfrom rest_framework.permissions import IsAuthenticated\nfrom rest_framework.response import Response\nfrom rest_framework import status\n\nfrom .services import AuthService\nfrom core.auth.utils import generate_tokens\nfrom core.exceptions.exceptions import CustomException\nimport logging\n\nlogger = logging.getLogger(__name__)\n\n\n@api_view(['POST'])\ndef health_check(request):\n    \"\"\"Health check endpoint.\"\"\"\n    return Response({\n        'status': 'healthy',\n        'message': 'Backend is running',\n        'timestamp': str(request.timestamp)\n    })\n\n\n@api_view(['POST'])\ndef register(request):\n    \"\"\"Register a new user.\"\"\"\n    try:\n        data = request.data\n        user = AuthService.register_user(data)\n        tokens = generate_tokens(user)\n        return Response({\n            'message': 'User registered successfully',\n            'user': {\n                'id': user.id,\n                'username': user.username,\n                'email': user.email\n            },\n            'tokens': tokens\n        }, status=status.HTTP_201_CREATED)\n    except CustomException as e:\n        return Response({\n            'error': {\n                'detail': e.default_detail,\n                'code': e.default_code\n            }\n        }, status=e.status_code)\n    except Exception as e:\n        logger.error(f\"Registration error: {str(e)}\")\n        return Response({\n            'error': {\n                'detail': 'An unexpected error occurred',\n                'code': 'internal_error'\n            }\n        }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)\n\n\n@api_view(['POST'])\ndef login(request):\n    \"\"\"Login user.\"\"\"\n    try:\n        data = request.data\n        user = AuthService.authenticate_user(data.get('email'), data.get('password'))\n        tokens = generate_tokens(user)\n        return Response({\n            'message': 'Login successful',\n            'user': {\n                'id': user.id,\n                'username': user.username,\n                'email': user.email\n            },\n            'tokens': tokens\n        })\n    except CustomException as e:\n        return Response({\n            'error': {\n                'detail': e.default_detail,\n                'code': e.default_code\n            }\n        }, status=e.status_code)\n    except Exception as e:\n        logger.error(f\"Login error: {str(e)}\")\n        return Response({\n            'error': {\n                'detail': 'An unexpected error occurred',\n                'code': 'internal_error'\n            }\n        }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)\n\n\n@api_view(['POST'])\@permission_classes([IsAuthenticated])\ndef profile(request):\n    \"\"\"Get user profile.\"\"\"\n    try:\n        user = AuthService.get_user_profile(request.user.id)\n        return Response({\n            'message': 'Profile retrieved successfully',\n            'user': {\n                'id': user.id,\n                'username': user.username,\n                'email': user.email,\n                'first_name': user.first_name,\n                'last_name': user.last_name,\n                'is_active': user.is_active,\n                'created_at': user.created_at.isoformat(),\n                'updated_at': user.updated_at.isoformat()\n            }\n        })\n    except CustomException as e:\n        return Response({\n            'error': {\n                'detail': e.default_detail,\n                'code': e.default_code\n            }\n        }, status=e.status_code)\n    except Exception as e:\n        logger.error(f\"Profile error: {str(e)}\")\n        return Response({\n            'error': {\n                'detail': 'An unexpected error occurred',\n                'code': 'internal_error'\n            }\n        }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)\n"